const now = new Date();
const month = now.getMonth() + 1; // 1-12

// Seasonal demand multipliers for Madison WI
const seasonalMultipliers = {
  1: 0.3, 2: 0.3, 3: 0.7,   // Winter/early spring
  4: 1.2, 5: 1.4, 6: 1.3,   // Peak spring
  7: 1.1, 8: 1.0, 9: 1.2,   // Summer/fall start
  10: 1.3, 11: 1.4, 12: 0.8 // Peak fall, pre-winter
};

const multiplier = seasonalMultipliers[month] || 1.0;

// Base pricing recommendations
const services = [
  { service: 'lawn-mowing', base_price: 45, unit: 'per visit' },
  { service: 'spring-cleanup', base_price: 250, unit: 'per service' },
  { service: 'fall-cleanup', base_price: 275, unit: 'per service' },
  { service: 'snow-removal', base_price: 75, unit: 'per visit' },
  { service: 'gutter-cleaning', base_price: 150, unit: 'per service' },
  { service: 'hardscaping', base_price: 1500, unit: 'per project' }
];

const recommendations = services.map(s => ({
  ...s,
  recommended_price: Math.round(s.base_price * multiplier),
  multiplier,
  season: month >= 4 && month <= 6 ? 'spring' : month >= 7 && month <= 9 ? 'summer' : month >= 10 && month <= 11 ? 'fall' : 'winter'
}));

return [{ json: { month, multiplier, recommendations, updated_at: now.toISOString() } }];
